import math

class GroundedPrompt:
    def __init__(self, chunks: list[str]):
        self.chunks = chunks
        self.vectors = [self._embed(c) for c in chunks]

    def _embed(self, text: str) -> dict:
        vec = {}
        for w in text.lower().split():
            vec[w] = vec.get(w, 0) + 1
        return vec

    def _cosine(self, a: dict, b: dict) -> float:
        shared = set(a) & set(b)
        dot = sum(a[w] * b[w] for w in shared)
        ma = math.sqrt(sum(v**2 for v in a.values()))
        mb = math.sqrt(sum(v**2 for v in b.values()))
        return dot / (ma * mb) if ma and mb else 0.0

    def _ranked(self, question: str) -> list[str]:
        q = self._embed(question)
        scored = [(c, self._cosine(q, v)) for c, v in zip(self.chunks, self.vectors)]
        scored.sort(key=lambda x: x[1], reverse=True)
        return [c for c, _ in scored]

